function makeCanvasResponsive() {
  const canvas = document.getElementById("canvas");
  const container = document.getElementById("animation_container");
  const stage = exportRoot.stage || stage;

  const designWidth = 1920;
  const designHeight = 1080;

  function resize() {
    const w = window.innerWidth;
    const h = window.innerHeight;
    const ratio = Math.min(w / designWidth, h / designHeight);

    const dpr = window.devicePixelRatio || 1;

    canvas.width = designWidth * ratio * dpr;
    canvas.height = designHeight * ratio * dpr;

    canvas.style.width = designWidth * ratio + "px";
    canvas.style.height = designHeight * ratio + "px";

    stage.scaleX = stage.scaleY = ratio * dpr;
    stage.update();
  }

  window.addEventListener("resize", resize);
  resize();
}

an.handleSoundStreamOnTick = function(event) {
	if(!event.paused){
		var stageChild = stage.getChildAt(0);
		if(!stageChild.paused || stageChild.ignorePause){
			stageChild.syncStreamSounds();
		}
	}
}
an.handleFilterCache = function(event) {
	if(!event.paused){
		var target = event.target;
		if(target){
			if(target.filterCacheList){
				for(var index = 0; index < target.filterCacheList.length ; index++){
					var cacheInst = target.filterCacheList[index];
					if((cacheInst.startFrame <= target.currentFrame) && (target.currentFrame <= cacheInst.endFrame)){
						cacheInst.instance.cache(cacheInst.x, cacheInst.y, cacheInst.w, cacheInst.h);
					}
				}
			}
		}
	}
}


